import{_ as e,o as a,c as r,ae as d}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"PAM Data Reference","description":"","frontmatter":{"title":"PAM Data Reference","slug":"predictive-aggregate-measurement-data-reference"},"headers":[],"relativePath":"marketer-hub/predictive-aggregate-measurement-data-reference.md","filePath":"marketer-hub/predictive-aggregate-measurement-data-reference.md"}'),o={name:"marketer-hub/predictive-aggregate-measurement-data-reference.md"};function i(s,t,h,n,l,u){return a(),r("div",null,[...t[0]||(t[0]=[d('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This technical reference shows the log-level data structures available when using Predictive Aggregate Measurement (PAM).</p><p>Whether you&#39;re a marketer evaluating what attribution data you&#39;ll have access to or a data analyst building custom reporting, these tables contain the information you need on the exact fields available in each scenario.</p><p>The tables in this reference illustrate the data that advertisers see in Branch reporting, as well as what ad networks receive in postbacks. They also show how enabling PAM for Advertisers and PAM for Publishers affects the data available to each party.</p><p>For a high-level overview of PAM and how to enable it, see our main <a href="./predictive-aggregate-measurement.html">PAM documentation</a>.</p><h2 id="attribution-scenarios" tabindex="-1">Attribution scenarios <a class="header-anchor" href="#attribution-scenarios" aria-label="Permalink to &quot;Attribution scenarios&quot;">​</a></h2><p>The following tables compare what attribution data is available to advertisers and ad networks as you move from pre-ATT environments through various PAM configurations.</p><h3 id="pre-att" tabindex="-1">Pre-ATT <a class="header-anchor" href="#pre-att" aria-label="Permalink to &quot;Pre-ATT&quot;">​</a></h3><p>This scenario assumes that a user either has not updated to iOS 14.5+ (pre-ATT), or they have gone through Apple&#39;s App Tracking Transparency (ATT) prompts and given consent to tracking in both the advertiser&#39;s app and the publisher&#39;s app where they saw the ad.</p><p><strong>Advertiser data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from SDK)</th><th>IDFV (user data from SDK)</th><th>Device (aggregate data from SDK)</th><th>Platform (aggregate data from SDK)</th><th>Country (aggregate data from SDK)</th></tr></thead><tbody><tr><td>11111</td><td>22222</td><td>iPhone 15</td><td>iOS</td><td>US</td></tr></tbody></table><p><strong>Publisher data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from link)</th><th>Campaign (aggregate data from ad network)</th><th>Creative (aggregate data from ad network)</th><th>Click ID (user data from ad network)</th><th>IP Address (user data from link)</th></tr></thead><tbody><tr><td>11111</td><td>Summer Blast</td><td>new_user_discount</td><td>333333</td><td>444.44.444.44</td></tr></tbody></table><p>In this case, all data is available. However, the majority of users opt out with ATT. The remaining examples in this guide focus on that scenario.</p><h3 id="post-att-with-opt-out" tabindex="-1">Post-ATT with opt-out <a class="header-anchor" href="#post-att-with-opt-out" aria-label="Permalink to &quot;Post-ATT with opt-out&quot;">​</a></h3><p>All of the tables in this section are related to cases where a user has gone through the ATT prompts for an app and decided to opt out, which is the most common behavior.</p><p>The tables demonstrate the trade-offs in attribution data when the user has opted out:</p><ul><li><strong>Without PAM</strong>:Minimal attribution data available.</li><li><strong>With PAM for Advertisers only</strong>:You gain predictive attribution insights in Branch, but limit what identifiers are shared with ad partners in postbacks.</li><li><strong>With both PAM for Advertisers and Publishers:</strong> Ad partners receive additional identifiers (like Click ID and IP Address) to optimize campaigns, but you may see fewer device-level identifiers in your own reporting.</li></ul><h4 id="without-pam" tabindex="-1">Without PAM <a class="header-anchor" href="#without-pam" aria-label="Permalink to &quot;Without PAM&quot;">​</a></h4><p>In this case, the user has opted out of ATT and the advertiser has not enabled PAM. As a result, all of the data from the publisher side is lost, and the IDFA from the advertiser side is lost as well.</p><p>Again, it is important to remember that most users decide to opt out when presented with ATT prompts. Without PAM, significant attribution data is left out of reporting.</p><p><strong>Advertiser data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from SDK)</th><th>IDFV (user data from SDK)</th><th>Device (aggregate data from SDK)</th><th>Platform (aggregate data from SDK)</th><th>Country (aggregate data from SDK)</th></tr></thead><tbody><tr><td>null</td><td>22222</td><td>iPhone 15</td><td>iOS</td><td>US</td></tr></tbody></table><p><strong>Publisher data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from link)</th><th>Campaign (aggregate data from ad network)</th><th>Creative (aggregate data from ad network)</th><th>Click ID (user data from ad network)</th><th>IP Address (user data from link)</th></tr></thead><tbody><tr><td>null</td><td>null</td><td>null</td><td>null</td><td>null</td></tr></tbody></table><h4 id="with-pam-for-advertisers" tabindex="-1">With PAM for Advertisers <a class="header-anchor" href="#with-pam-for-advertisers" aria-label="Permalink to &quot;With PAM for Advertisers&quot;">​</a></h4><p>PAM has two components: PAM for Advertisers and PAM for Publishers. They have separate control switches in Branch.</p><p>PAM for Advertisers takes the privacy-preserving step of removing publisher user data while still capturing publisher aggregate data, so you can gather valuable information about which of your campaigns and creatives are performing the best.</p><p>PAM for Advertisers is turned on at <a href="./predictive-aggregate-measurement.html#enable-pam-at-the-orglevel">either the app or org level</a>.</p><p><strong>Advertiser data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from SDK)</th><th>IDFV (user data from SDK)</th><th>Device (aggregate data from SDK)</th><th>Platform (aggregate data from SDK)</th><th>Country (aggregate data from SDK)</th></tr></thead><tbody><tr><td>null</td><td>22222</td><td>iPhone 15</td><td>iOS</td><td>US</td></tr></tbody></table><p><strong>Publisher data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from link)</th><th>Campaign (aggregate data from ad network)</th><th>Creative (aggregate data from ad network)</th><th>Click ID (user data from ad network)</th><th>IP Address (user data from link)</th></tr></thead><tbody><tr><td>null</td><td>Summer Blast</td><td>new_user_discount</td><td>null</td><td>null</td></tr></tbody></table><h4 id="with-pam-for-publishers" tabindex="-1">With PAM for Publishers <a class="header-anchor" href="#with-pam-for-publishers" aria-label="Permalink to &quot;With PAM for Publishers&quot;">​</a></h4><p>The second component of PAM is PAM for Publishers, and it controls what data is shared with ad partner in Postbacks.</p><p>PAM for Publishers removes advertiser user data but preserves advertiser aggregate data. With this approach, ad networks get click ID and IP address for campaign optimization, but you may lose some device identifiers.</p><p>PAM for Publishers is turned on at <a href="./predictive-aggregate-measurement.html#enable-pam-for-publishers">the ad partner level</a>, in the configuration section for each ad partner.</p><p><strong>Advertiser data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from SDK)</th><th>IDFV (user data from SDK)</th><th>Device (aggregate data from SDK)</th><th>Platform (aggregate data from SDK)</th><th>Country (aggregate data from SDK)</th></tr></thead><tbody><tr><td>null</td><td>null</td><td>iPhone 15</td><td>iOS</td><td>US</td></tr></tbody></table><p><strong>Publisher data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from link)</th><th>Campaign (aggregate data from ad network)</th><th>Creative (aggregate data from ad network)</th><th>Click ID (user data from ad network)</th><th>IP Address (user data from link)</th></tr></thead><tbody><tr><td>null</td><td>Summer Blast</td><td>new_user_discount</td><td>333333</td><td>444.44.444.44</td></tr></tbody></table><h2 id="pam-reporting" tabindex="-1">PAM reporting <a class="header-anchor" href="#pam-reporting" aria-label="Permalink to &quot;PAM reporting&quot;">​</a></h2><p>This section illustrates what the advertiser and the ad network will see when both PAM for Advertisers and Publishers is enabled.</p><h3 id="what-advertisers-see" tabindex="-1">What advertisers see <a class="header-anchor" href="#what-advertisers-see" aria-label="Permalink to &quot;What advertisers see&quot;">​</a></h3><p><strong>Advertiser data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from SDK)</th><th>IDFV (user data from SDK)</th><th>Device (aggregate data from SDK)</th><th>Platform (aggregate data from SDK)</th><th>Country (aggregate data from SDK)</th></tr></thead><tbody><tr><td>-</td><td>22222</td><td>iPhone 15</td><td>iOS</td><td>US</td></tr></tbody></table><p><strong>Publisher data</strong></p><table tabindex="0"><thead><tr><th>Campaign (aggregate data from ad network)</th><th>Creative (aggregate data from ad network)</th><th>PAM Enabled</th></tr></thead><tbody><tr><td>Summer Blast</td><td>new_user_discount</td><td>TRUE</td></tr></tbody></table><h3 id="what-ad-networks-see" tabindex="-1">What ad networks see <a class="header-anchor" href="#what-ad-networks-see" aria-label="Permalink to &quot;What ad networks see&quot;">​</a></h3><p>Please note that this reporting structure requires PAM for Publishers to be turned on for this particular ad network.</p><p><strong>Advertiser data</strong></p><table tabindex="0"><thead><tr><th>Device (aggregate data from SDK)</th><th>Platform (aggregate data from SDK)</th><th>Country (aggregate data from SDK)</th></tr></thead><tbody><tr><td>iPhone 15</td><td>iOS</td><td>US</td></tr></tbody></table><p><strong>Publisher data</strong></p><table tabindex="0"><thead><tr><th>IDFA (user data from link)</th><th>Campaign (aggregate data from ad network)</th><th>Creative (aggregate data from ad network)</th><th>Click ID (user data from ad network)</th><th>IP Address (user data from link)</th></tr></thead><tbody><tr><td>null</td><td>Summer Blast</td><td>new_user_discount</td><td>333333</td><td>444.44.444.44</td></tr></tbody></table>',54)])])}const m=e(o,[["render",i]]);export{p as __pageData,m as default};
